```kotlin
import androidx.lifecycle.LiveData
import androidx.lifecycle.MutableLiveData
import androidx.lifecycle.ViewModel
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.launch

// Предположим, у нас есть модель Post
data class Post(val id: Int, val title: String, val content: String)

// Интерфейс репозитория
interface PostRepository {
    fun getPosts(): LiveData<List<Post>>
}

// MainViewModel
class MainViewModel(private val repository: PostRepository) : ViewModel() {

    // Public LiveData для отображения в UI
    private val _posts = MutableLiveData<List<Post>>()
    val posts: LiveData<List<Post>> get() = _posts

    // Метод для загрузки постов
    fun loadPosts() {
        viewModelScope.launch {
            repository.getPosts().observeForever { newPosts ->
                _posts.value = newPosts
            }
        }
    }
}
```

### Пояснения:
- `repository.getPosts()` возвращает `LiveData<List<Post>>`.
- В `MainViewModel` используется `viewModelScope.launch` для асинхронной загрузки данных.
- `_posts` — внутренний `MutableLiveData`, который обновляется при получении новых данных.
- `posts` — публичный `LiveData`, который используется в разметке (например, RecyclerView).
- Метод `loadPosts()` запускает загрузку постов из репозитория.

