const templatePath = path.join(__dirname, 'src/templates');
// Путь к исходным парсерам
const parserPath = path.join(__dirname, 'src/parsers');

// Сборка шаблонов
function compileTemplates() {
  return gulp.src(`${templatePath}/index.handlebars`)
    .pipe(handlebars())
    .pipe(handlebars.preprocess(function (handlebarsContent) {
      // Добавляем обработку переменных из парсеров
      const parsed = parso(handlebarsContent).run();
      return parsed.content;
    }))
    .pipe(gulp.dest(path.join(__dirname, 'dist', 'templates')));
}

// Генерация исходных файлов (например, из PHP)
function generateParsers() {
  return gulp.src(`${parserPath}/*.js`)
    .pipe(clean({ dest: __dirname })) // Очистка старых файлов
    .pipe(rename({ suffix: '.parsed' })) // Добавляем суффикс
    .pipe(gulp.dest(__dirname, 'dist', 'parsers'));
}

// Создание публичного каталога
function buildPublicCatalog() {
  return gulp.src('dist/*')
    .pipe(clean({ dest: __dirname, force: true })) // Очистка старого каталога
    .pipe(rename({ dirname: 'public' })) // Перемещаем файлы в public
    .toFile('dist/public/index.html') // Пример для HTML
    .pipe(gulp.dest('dist/public'));
